import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import axios from 'axios';

function UASTLChart({ range }) {
    const d3Container = useRef(null);

    useEffect(() => {
        if (!d3Container.current) return;

        const width = d3Container.current.clientWidth;
        const height = d3Container.current.clientHeight;
        const margin = { top: 40, right: 30, bottom: 60, left: 80 };
        const chartW = width - margin.left - margin.right;
        const chartH = height - margin.top - margin.bottom;

        // 清除之前的內容
        d3.select(d3Container.current).selectAll('*').remove();

        Promise.all([
            axios.get('http://localhost:3001/api/uastl'),
            d3.csv('/CoolWarmFloat257.csv', d => ({
                scalar: +d.Scalar,
                r: +d.R,
                g: +d.G,
                b: +d.B
            }))
        ]).then(([res, cmapData]) => {
            let data = res.data;
            if (!data || data.length === 0) return;

            // 應用range過濾
            if (range && range.length === 2) {
                data = data.slice(range[0], range[1] + 1);
            }

            const n = data.length;

            // 獲取所有必要參數
            const seasonalKeys = Object.keys(data[0]).filter(k => k.startsWith('seasonal') && k.endsWith('_mean'));
            const L = seasonalKeys.length;
            const numComponents = 3 + L;
            const numSamples = data[0].num_samples_added || 3;
            const p_used = data[0].p_used ? data[0].p_used.split(',').map(Number) : [7, 90, 365];
            const coPoint = data[0].coPoint_used ? +data[0].coPoint_used - 1 : null;

            // 創建coolwarm顏色映射（更精確的插值）
            const coolwarmScale = d3.scaleSequential()
                .domain([-1, 1])
                .interpolator(t => {
                    // 將[-1,1]範圍映射到[0,256]索引
                    const normalizedT = (t + 1) / 2; // 轉換到[0,1]範圍
                    const idx = Math.round(normalizedT * 256);
                    const clampedIdx = Math.max(0, Math.min(256, idx));
                    const colorData = cmapData[clampedIdx];
                    return `rgb(${Math.round(colorData.r * 255)}, ${Math.round(colorData.g * 255)}, ${Math.round(colorData.b * 255)})`;
                });

            // 樣本路徑顏色（更多彩的顏色）
            const sampleColors = [
                '#FF6B6B', '#4ECDC4', '#45B7D1', '#96CEB4', '#FFEAA7',
                '#DDA0DD', '#98D8C8', '#F7DC6F', '#BB8FCE', '#85C1E9'
            ];

            // 置信區間設定
            const sigmaLevels = {
                '50%': 0.674490,
                '99%': 2.575829
            };

            const bandColors = {
                '50%': 'rgba(135, 206, 250, 0.5)', // sky blue
                '99%': 'rgba(173, 216, 230, 0.3)'  // light blue
            };

            // 主線顏色（深藍）
            const meanColor = '#1a237e';

            // 組件標題
            const titles = [
                'Input Data',
                'Trend Component',
                ...seasonalKeys.map((k, i) => `Seasonal Component ${i + 1} (p=${p_used[i] || 'N/A'})`),
                'Residual Component'
            ];

            // 組件數據鍵映射
            const componentKeys = [
                'input',
                'trend',
                ...seasonalKeys.map(k => k.replace('_mean', '').replace('seasonal', 'seasonal')),
                'residual'
            ];

            // 創建SVG
            const svg = d3.select(d3Container.current)
                .append('svg')
                .attr('width', width)
                .attr('height', height)
                .style('background', 'linear-gradient(to bottom, #fafafa, #f0f0f0)');

            // 添加主標題
            svg.append('text')
                .attr('x', width / 2)
                .attr('y', 25)
                .attr('text-anchor', 'middle')
                .attr('font-size', 16)
                .attr('font-weight', 'bold')
                .attr('font-family', 'Arial')
                .attr('fill', '#333')
                .text('UASTL Decomposition Results (Python Replica)');

            const subplotH = chartH / numComponents;

            // 繪製每個組件
            componentKeys.forEach((compKey, i) => {
                const g = svg.append('g')
                    .attr('transform', `translate(${margin.left}, ${margin.top + i * subplotH})`);

                // 獲取數據
                const meanKey = `${compKey}_mean`;
                const stdKey = `${compKey}_std`;
                const corrKey = `corr_${compKey}`;

                const mean = data.map(d => +d[meanKey]).filter(v => !isNaN(v));
                const std = data.map(d => +d[stdKey]).filter(v => !isNaN(v));
                const corr = data.map(d => +d[corrKey]).filter(v => !isNaN(v));

                if (mean.length === 0) return;

                // 確保數據長度一致
                const dataLength = Math.min(mean.length, std.length, corr.length);
                const meanData = mean.slice(0, dataLength);
                const stdData = std.slice(0, dataLength);
                const corrData = corr.slice(0, dataLength);

                // Y軸比例尺（為底部相關性色帶留更多空間）
                const yMin = d3.min(meanData, (d, j) => d - sigmaLevels['99%'] * stdData[j]);
                const yMax = d3.max(meanData, (d, j) => d + sigmaLevels['99%'] * stdData[j]);
                const yRange = yMax - yMin;
                const yExtension = yRange * 0.25; // 為相關性色帶留25%空間

                const y = d3.scaleLinear()
                    .domain([yMin - yExtension, yMax])
                    .nice()
                    .range([subplotH - 50, 10]);

                // X軸比例尺
                const x = d3.scaleLinear()
                    .domain([0, dataLength - 1])
                    .range([0, chartW]);

                // 計算相關性色帶的基準位置和最大高度
                const corrBaseY = y(yMin - yExtension * 0.8);
                const maxCorrHeight = yExtension * 0.6;

                // 繪製置信區間帶（從大到小）
                ['99%', '50%'].forEach(level => {
                    const areaData = meanData.map((m, j) => ({
                        x: x(j),
                        y0: y(m - sigmaLevels[level] * stdData[j]),
                        y1: y(m + sigmaLevels[level] * stdData[j])
                    }));

                    g.append('path')
                        .datum(areaData)
                        .attr('fill', bandColors[level])
                        .attr('stroke', 'none')
                        .attr('d', d3.area()
                            .x(d => d.x)
                            .y0(d => d.y0)
                            .y1(d => d.y1)
                            .curve(d3.curveLinear)
                        );
                });

                // 繪製樣本路徑（spaghetti plots）- 在主線之前繪製
                for (let s = 1; s <= numSamples; s++) {
                    const sampleKey = `sample${s}_${compKey}`;
                    if (data[0][sampleKey] !== undefined) {
                        const sampleData = data.map(d => +d[sampleKey]).filter(v => !isNaN(v));
                        if (sampleData.length > 0) {
                            g.append('path')
                                .datum(sampleData.slice(0, dataLength))
                                .attr('fill', 'none')
                                .attr('stroke', sampleColors[(s - 1) % sampleColors.length])
                                .attr('stroke-width', 1.0)
                                .attr('opacity', 0.8)
                                .attr('d', d3.line()
                                    .x((d, idx) => x(idx))
                                    .y(d => y(d))
                                    .curve(d3.curveLinear)
                                );
                        }
                    }
                }

                // 繪製均值線（主線）- 在樣本路徑之後繪製，較細的線條
                g.append('path')
                    .datum(meanData)
                    .attr('fill', 'none')
                    .attr('stroke', meanColor)
                    .attr('stroke-width', 1.2)
                    .attr('d', d3.line()
                        .x((d, idx) => x(idx))
                        .y(d => y(d))
                        .curve(d3.curveLinear)
                    );

                // 繪製底部相關性色帶（matlab風格：每格高度反映不確定性）
                const maxCorr = d3.max(corrData, d => Math.abs(d)) || 1;

                corrData.forEach((cval, idx) => {
                    if (!isNaN(cval) && idx < dataLength) {
                        // 限制相關性值在[-1, 1]範圍內
                        const clampedCorr = Math.max(-1, Math.min(1, cval));

                        // 計算該點的不確定性高度（基於標準差）
                        const uncertaintyHeight = (stdData[idx] / d3.max(stdData)) * maxCorrHeight;

                        // 計算矩形的y位置和高度
                        let rectY, rectHeight;
                        if (clampedCorr >= 0) {
                            rectY = corrBaseY - uncertaintyHeight;
                            rectHeight = uncertaintyHeight * clampedCorr;
                        } else {
                            rectY = corrBaseY;
                            rectHeight = uncertaintyHeight * Math.abs(clampedCorr);
                        }

                        g.append('rect')
                            .attr('x', x(idx) - chartW / dataLength / 2)
                            .attr('y', rectY)
                            .attr('width', Math.max(1, chartW / dataLength))
                            .attr('height', Math.max(1, Math.abs(rectHeight)))
                            .attr('fill', coolwarmScale(clampedCorr))
                            .attr('stroke', 'none');
                    }
                });

                // 繪製coPoint垂直線
                if (coPoint !== null && coPoint >= 0 && coPoint < dataLength) {
                    g.append('line')
                        .attr('x1', x(coPoint))
                        .attr('x2', x(coPoint))
                        .attr('y1', 10)
                        .attr('y2', subplotH - 50)
                        .attr('stroke', 'black')
                        .attr('stroke-width', 2);
                }

                // 添加組件標題
                g.append('text')
                    .attr('x', chartW / 2)
                    .attr('y', 0)
                    .attr('text-anchor', 'middle')
                    .attr('font-size', 14)
                    .attr('font-weight', 'bold')
                    .attr('font-family', 'Arial')
                    .attr('fill', '#333')
                    .text(titles[i]);

                // 添加Y軸
                g.append('g')
                    .call(d3.axisLeft(y)
                        .ticks(4)
                        .tickFormat(d3.format('.2f'))
                    )
                    .selectAll('text')
                    .attr('fill', '#555')
                    .attr('font-size', 10)
                    .attr('font-family', 'Arial');

                // 添加零線（對於季節性和殘差組件）
                if (i > 1) {
                    g.append('line')
                        .attr('x1', 0)
                        .attr('x2', chartW)
                        .attr('y1', y(0))
                        .attr('y2', y(0))
                        .attr('stroke', '#666')
                        .attr('stroke-width', 0.5)
                        .attr('stroke-dasharray', '2,2')
                        .attr('opacity', 0.7);
                }

                // 在最後一個子圖添加X軸
                if (i === componentKeys.length - 1) {
                    g.append('g')
                        .attr('transform', `translate(0, ${subplotH - 50})`)
                        .call(d3.axisBottom(x)
                            .ticks(8)
                            .tickFormat(d => `${d}`)
                        )
                        .selectAll('text')
                        .attr('fill', '#555')
                        .attr('font-size', 10)
                        .attr('font-family', 'Arial');

                    // X軸標籤
                    g.append('text')
                        .attr('x', chartW / 2)
                        .attr('y', subplotH - 10)
                        .attr('text-anchor', 'middle')
                        .attr('font-size', 12)
                        .attr('font-family', 'Arial')
                        .attr('fill', '#333')
                        .text('Time Index (Days since start)');
                }
            });

        }).catch(error => {
            console.error('Error loading UASTL data:', error);
        });

    }, [range]);

    return (
        <div style={{ width: '100%', height: '100%', background: 'none' }}>
            <div ref={d3Container} style={{
                width: '100%',
                height: '100%',
                borderRadius: '12px',
                overflow: 'hidden',
                position: 'relative',
                background: '#ffffff'
            }} />
        </div>
    );
}

export default UASTLChart;
